import net from 'net';
import fs from 'fs';
import path from 'path';
import { spawn } from 'child_process';

interface DaemonResponse {
    status: number;
    message: string;
    data: any;
}

interface PendingRequest {
    resolve: (r: DaemonResponse) => void;
    reject: (e: Error) => void;
    timer: NodeJS.Timeout;
}

/**
 * TCP client for the query-engine daemon (server mode).
 *
 * Instead of spawning a new engine process per query (30-80ms overhead),
 * the daemon keeps the engine alive with warm connection pools and serves
 * requests over a local TCP socket in <1ms. One daemon per database name.
 */
export class DaemonClient {
    private static registry: Map<string, DaemonClient> = new Map();

    private name: string;
    private binaryPath: string;
    private engineArgs: string[];
    private socket: net.Socket | null = null;
    private buffer = '';
    private pending: PendingRequest[] = [];
    private starting: Promise<boolean> | null = null;
    private requestTimeout: number;

    private constructor(name: string, binaryPath: string, engineArgs: string[], requestTimeout = 30000) {
        this.name = name;
        this.binaryPath = binaryPath;
        this.engineArgs = engineArgs;
        this.requestTimeout = requestTimeout;
    }

    static get(name: string, binaryPath: string, engineArgs: string[]): DaemonClient {
        let client = this.registry.get(name);
        if (!client) {
            client = new DaemonClient(name, binaryPath, engineArgs);
            this.registry.set(name, client);
        }
        return client;
    }

    static isEnabled(): boolean {
        const flag = process.env.DBCUBE_DAEMON;
        if (flag === '0' || flag === 'false') return false;
        return true; // ON by default — fastest path with automatic fallback
    }

    private portfilePath(): string {
        return path.join(process.cwd(), '.dbcube', 'daemon', `${this.name}.json`);
    }

    private lockfilePath(): string {
        return path.join(process.cwd(), '.dbcube', 'daemon', `${this.name}.lock`);
    }

    /**
     * Exclusive-create lock so two processes never spawn two daemons for the
     * same database at once. Stale locks (crashed starter) expire after 15s.
     */
    private acquireSpawnLock(): boolean {
        const lockPath = this.lockfilePath();
        try {
            fs.mkdirSync(path.dirname(lockPath), { recursive: true });
            const fd = fs.openSync(lockPath, 'wx');
            fs.writeSync(fd, String(process.pid));
            fs.closeSync(fd);
            return true;
        } catch {
            try {
                const age = Date.now() - fs.statSync(lockPath).mtimeMs;
                if (age > 15000) {
                    fs.unlinkSync(lockPath);
                    return this.acquireSpawnLock();
                }
            } catch { /* lock vanished between checks */ }
            return false;
        }
    }

    private releaseSpawnLock(): void {
        try { fs.unlinkSync(this.lockfilePath()); } catch { /* already gone */ }
    }

    /**
     * Ensures a usable daemon connection. Returns false when the daemon
     * can't be used (old binary, startup failure) so callers fall back
     * to one-shot spawn mode.
     */
    async ensure(): Promise<boolean> {
        if (this.socket && !this.socket.destroyed) return true;
        if (this.starting) return this.starting;

        this.starting = this.connectOrStart().catch(() => false);
        const result = await this.starting;
        this.starting = null;
        return result;
    }

    private async connectOrStart(): Promise<boolean> {
        // 1. Try an existing daemon via portfile
        const port = this.readPortfile();
        if (port && await this.tryConnect(port)) return true;

        // 2. Stale portfile — remove and start a fresh daemon. The spawn lock
        // ensures only one process boots the daemon; the rest just wait for
        // the new portfile to appear.
        const gotLock = this.acquireSpawnLock();
        try {
            if (gotLock) {
                try { fs.unlinkSync(this.portfilePath()); } catch { /* not there */ }
                this.spawnDaemon();
            }

            // 3. Poll the portfile while the daemon boots (up to 10s)
            const deadline = Date.now() + 10000;
            while (Date.now() < deadline) {
                await new Promise(r => setTimeout(r, 150));
                const newPort = this.readPortfile();
                if (newPort && await this.tryConnect(newPort)) return true;
            }
            return false;
        } finally {
            if (gotLock) this.releaseSpawnLock();
        }
    }

    private readPortfile(): number | null {
        try {
            const raw = fs.readFileSync(this.portfilePath(), 'utf8');
            const info = JSON.parse(raw);
            const port = info?.port;
            return Number.isInteger(port) && port > 0 && port <= 65535 ? port : null;
        } catch {
            return null;
        }
    }

    private spawnDaemon(): void {
        const child = spawn(this.binaryPath, [...this.engineArgs, '--action', 'server', '--tcp-port', '9944'], {
            detached: true,
            stdio: 'ignore',
            cwd: process.cwd(),
        });
        child.unref();
    }

    private tryConnect(port: number): Promise<boolean> {
        return new Promise((resolve) => {
            const socket = net.createConnection({ host: '127.0.0.1', port }, async () => {
                socket.setNoDelay(true);
                this.attach(socket);
                // Verify it's a current-generation daemon (supports ping).
                // Short timeout: if the port was reused by an unrelated
                // process, we must not hang the full request timeout.
                try {
                    const pong = await this.send({ action: 'ping' }, 2000);
                    resolve(pong.status === 200);
                } catch {
                    this.detach();
                    resolve(false);
                }
            });
            socket.once('error', () => resolve(false));
            socket.setTimeout(3000, () => { socket.destroy(); resolve(false); });
        });
    }

    private attach(socket: net.Socket): void {
        this.socket = socket;
        this.buffer = '';
        socket.setTimeout(0);
        socket.on('data', (chunk: Buffer | string) => this.onData(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk)));
        socket.on('close', () => this.detach());
        socket.on('error', () => this.detach());
    }

    private detach(): void {
        if (this.socket) {
            this.socket.removeAllListeners();
            this.socket.destroy();
            this.socket = null;
        }
        // Fail anything still in flight
        for (const req of this.pending.splice(0)) {
            clearTimeout(req.timer);
            req.reject(new Error('Daemon connection lost'));
        }
    }

    private onData(chunk: Buffer): void {
        this.buffer += chunk.toString('utf8');
        let idx: number;
        while ((idx = this.buffer.indexOf('\n')) !== -1) {
            const line = this.buffer.slice(0, idx).trim();
            this.buffer = this.buffer.slice(idx + 1);
            if (!line) continue;
            const marker = line.indexOf('PROCESS_RESPONSE:');
            if (marker === -1) continue; // engine log noise
            const jsonPart = line.slice(marker + 'PROCESS_RESPONSE:'.length);
            const req = this.pending.shift();
            if (!req) continue;
            clearTimeout(req.timer);
            try {
                req.resolve(JSON.parse(jsonPart));
            } catch (e: any) {
                req.reject(new Error(`Invalid daemon response: ${e.message}`));
            }
        }
    }

    /**
     * Sends a request to the daemon. Responses arrive in FIFO order on the
     * single socket, so pending requests resolve in send order.
     */
    send(payload: Record<string, any>, timeoutMs?: number): Promise<DaemonResponse> {
        return new Promise((resolve, reject) => {
            if (!this.socket || this.socket.destroyed) {
                reject(new Error('Daemon not connected'));
                return;
            }
            const timer = setTimeout(() => {
                const i = this.pending.findIndex(p => p.timer === timer);
                if (i !== -1) this.pending.splice(i, 1);
                reject(new Error('Daemon request timeout'));
                // La respuesta tardía de este request llegaría igual y se
                // emparejaría con el siguiente pending (FIFO desincronizado,
                // datos cruzados). La conexión ya no es confiable: descartarla.
                this.detach();
            }, timeoutMs ?? this.requestTimeout);

            this.pending.push({ resolve, reject, timer });
            this.socket.write(JSON.stringify(payload) + '\n');
        });
    }

    async execute(dml: object, txId?: string): Promise<DaemonResponse> {
        const payload: Record<string, any> = { action: 'execute', dml: JSON.stringify(dml) };
        if (txId) payload.tx_id = txId;
        return this.send(payload);
    }

    async raw(query: string, params: any[] = [], txId?: string): Promise<DaemonResponse> {
        const payload: Record<string, any> = { action: 'raw', query, params };
        if (txId) payload.tx_id = txId;
        return this.send(payload);
    }

    async begin(): Promise<string> {
        const res = await this.send({ action: 'begin' });
        if (res.status !== 200 || !res.data?.tx_id) {
            throw new Error(res.message || 'Failed to begin transaction');
        }
        return res.data.tx_id;
    }

    async commit(txId: string): Promise<void> {
        const res = await this.send({ action: 'commit', tx_id: txId });
        if (res.status !== 200) throw new Error(res.message || 'Failed to commit transaction');
    }

    async rollback(txId: string): Promise<void> {
        const res = await this.send({ action: 'rollback', tx_id: txId });
        if (res.status !== 200) throw new Error(res.message || 'Failed to rollback transaction');
    }

    async shutdown(): Promise<void> {
        try { await this.send({ action: 'shutdown' }); } catch { /* daemon exits mid-response */ }
        this.detach();
        try { fs.unlinkSync(this.portfilePath()); } catch { /* already gone */ }
    }
}

export default DaemonClient;
